"use server";

import { createClient } from "@/lib/supabase/server";
import {
  getUserFromClaims,
  type AuthActionResult,
  type LoginFormData,
  type SignupFormData,
} from "@/types/authtypes";

export async function signInWithEmail(
  data: LoginFormData,
): Promise<AuthActionResult> {
  const supabase = await createClient();
  const {
    data: { user },
    error,
  } = await supabase.auth.signInWithPassword({
    email: data.email,
    password: data.password,
  });
  if (error || !user) {
    return { ok: false, message: error?.message };
  }
  return { ok: true, redirect: "/dashboard" };
}

export async function signUpWithEmail(
  data: SignupFormData,
): Promise<AuthActionResult> {
  const supabase = await createClient();
  const { error } = await supabase.auth.signUp({
    email: data.email,
    password: data.password,
    options: {
      data: {
        name: data.name,
        full_name: data.name,
      },
    },
  });
  if (error) {
    return { ok: false, message: error?.message };
  }
  return { ok: true, redirect: "/confirm" };
}

export async function getUserAccessToken(): Promise<
  { token: string } | { message: string; redirect: string }
> {
  const supabase = await createClient();
  try {
    const {
      data: { session },
      error,
    } = await supabase.auth.getSession();
    if (error || !session) {
      return {
        message: error?.message ?? "Failed to get session",
        redirect: "/",
      };
    }
    return { token: session.access_token };
  } catch (err: unknown) {
    if (err instanceof Error) {
      return { message: err.message, redirect: "/" };
    }
    return { message: "Unknown error", redirect: "/" };
  }
}

export async function getUserClaims(): Promise<
  { user: ReturnType<typeof getUserFromClaims> } | null
> {
  const supabase = await createClient();
  try {
    const { data, error } = await supabase.auth.getClaims();
    if (error || !data?.claims) {
      return null;
    }
    return {
      user: getUserFromClaims(data.claims as Record<string, unknown>),
    };
  } catch {
    return null;
  }
}
